-- ── BRANDS ───────────────────────────────────────────────────
INSERT INTO brands (id, slug, name, tagline, description, founded, origin, cover_url) VALUES
('b1000000-0000-0000-0000-000000000001','zara','Zara','Fashion for the now','Zara is a Spanish apparel retailer known for its fast-fashion sensibility and accessible luxury aesthetic. Each season brings trend-forward pieces at everyday prices.','1975','Spain','https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=1200&q=80'),
('b1000000-0000-0000-0000-000000000002','toteme','Toteme','Defined by simplicity','Toteme is a Stockholm-based house offering a refined, pared-back wardrobe built around clean lines, quality fabrics, and quiet confidence.','2014','Sweden','https://images.unsplash.com/photo-1490481651871-ab68de25d43d?w=1200&q=80'),
('b1000000-0000-0000-0000-000000000003','jacquemus','Jacquemus','South of France','Jacquemus is a Parisian label celebrated for its playful minimalism, oversized sun hats, and micro-bags — a perpetual summer state of mind.','2009','France','https://images.unsplash.com/photo-1469334031218-e382a71b716b?w=1200&q=80'),
('b1000000-0000-0000-0000-000000000004','aritzia','Aritzia','Everyday luxury','Aritzia is a Canadian fashion boutique offering elevated everyday pieces through quality fabrics, thoughtful fit, and understated modern design.','1984','Canada','https://images.unsplash.com/photo-1445205170230-053b83016050?w=1200&q=80'),
('b1000000-0000-0000-0000-000000000005','cos','COS','Modern design, longer lasting','COS creates considered, functional wardrobe essentials built around architectural silhouettes, premium materials, and a commitment to lasting quality.','2007','United Kingdom','https://images.unsplash.com/photo-1515886657613-9f3515b0c78f?w=1200&q=80');

